+      const message = error instanceof Error ? error.message : String(error);
+      this.logger.error(`Failed to send SMS for notification ${notificationId}: ${message}`);
+
+      return {
+        success: false,
+        notificationId,
+        channel: 'sms',
+        error: message,
+      };
+    }
+  }
