/**
 * SMS notification adapter — delivers notifications via SMS.
 *
 * Implements the NotificationAdapter interface with:
 * - Phone number validation and normalization
 * - Message formatting (SMS has character limits, so body is concise)
 * - Configurable send behavior via an SmsTransport abstraction
 *
 * In production, provide a real SmsTransport (e.g., Twilio, AWS SNS).
 * For testing, use the built-in InMemorySmsTransport.
 *
 * NOTE: User preferences were designed assuming email-only channels.
 * The preferences model (src/models/user-preferences.ts) and PreferencesService
 * need to be updated to support per-channel preferences (sms enabled/disabled,
 * per-category subscriptions for SMS, etc.). Until then, SMS notifications
 * bypass preference checks in NotificationService.send().
 * See decision 01KN71XFTQ8WSRFKN1VA8A5DMG — its assumption "Email is currently
 * the only notification channel" is no longer valid.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Represents a formatted SMS message ready for sending.
 */
export interface SmsMessage {
  to: string;
  body: string;
}

/**
 * Transport interface for actually sending SMS messages.
 * Implement this to integrate with Twilio, AWS SNS, etc.
 */
export interface SmsTransport {
  sendSms(message: SmsMessage): Promise<{ messageId: string; accepted: boolean }>;
}

/**
 * In-memory transport for testing. Records all sent SMS messages.
 */
export class InMemorySmsTransport implements SmsTransport {
  readonly sent: SmsMessage[] = [];

  async sendSms(message: SmsMessage): Promise<{ messageId: string; accepted: boolean }> {
    this.sent.push(message);
    return { messageId: `sms-${this.sent.length}`, accepted: true };
  }

  clear(): void {
    this.sent.length = 0;
  }
}

/**
 * A transport that always fails, for testing error paths.
 */
export class FailingSmsTransport implements SmsTransport {
  constructor(private errorMessage = 'SMS gateway unavailable') {}

  async sendSms(_message: SmsMessage): Promise<{ messageId: string; accepted: boolean }> {
    throw new Error(this.errorMessage);
  }
}

/**
 * Configuration for the SMS adapter.
 */
export interface SmsAdapterConfig {
  fromNumber: string;
  transport: SmsTransport;
}

/**
 * Validate that a string looks like a valid phone number.
 * Accepts E.164 format: +{country code}{number}, 8-15 digits total.
 */
function isValidPhoneNumber(phone: string): boolean {
  return /^\+[1-9]\d{7,14}$/.test(phone);
}

/**
 * Format an SMS body from a notification payload.
 * Keeps messages concise for SMS character limits.
 */
function formatSmsBody(payload: NotificationPayload): string {
  return `${payload.subject}\n${payload.body}`;
}

export class SmsAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');

  constructor(private config: SmsAdapterConfig) {}

  /**
   * Resolve and validate the recipient phone number.
   * Returns the normalized phone number, or throws if invalid.
   */
  resolveRecipient(recipient: string): string {
    const normalized = recipient.trim();
    if (!isValidPhoneNumber(normalized)) {
      throw new Error(`Invalid phone number: ${recipient}`);
    }
    return normalized;
  }

  /**
   * Format a notification payload into an SMS message.
   */
  formatMessage(payload: NotificationPayload): SmsMessage {
    const to = this.resolveRecipient(payload.recipient);
    return {
      to,
      body: formatSmsBody(payload),
    };
  }

  /**
   * Send an SMS notification.
   *
   * 1. Resolves the recipient phone number
   * 2. Formats the message body
   * 3. Sends via the configured transport
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const notificationId = payload.metadata?.notificationId ?? 'unknown';

    try {
      const message = this.formatMessage(payload);

      this.logger.info(
        `Sending SMS from ${this.config.fromNumber} to ${message.to}`,
      );

      const result = await this.config.transport.sendSms(message);

      this.logger.info(
        `SMS sent successfully: messageId=${result.messageId}, notificationId=${notificationId}`,
      );

      return {
        success: result.accepted,
        notificationId,
        channel: 'sms',
      };
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      this.logger.error(`Failed to send SMS for notification ${notificationId}: ${message}`);

      return {
        success: false,
        notificationId,
        channel: 'sms',
        error: message,
      };
    }
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  SmsAdapter,
  InMemorySmsTransport,
